local function decode(s)local b='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'local t=''local i=1 while i<=#s do local a=b:find(s:sub(i,i))-1 local c=b:find(s:sub(i+1,i+1))-1 local d=b:find(s:sub(i+2,i+2))-1 local e=b:find(s:sub(i+3,i+3))-1 local x=(a*4)+(c//16)local y=((c%16)*16)+(d//4)local z=((d%4)*64)+e t=t..string.char(x)if y~=0 then t=t..string.char(y)end if z~=0 then t=t..string.char(z)end i=i+4 end return t end load(decode('cHJpbnQoImhlbGxvIikK'))()